# Basic Context-Free Grammar Parser for Arithmetic Expressions
# Grammar: E -> E + T | T, T -> T * F | F, F -> ( E ) | id

class CFGParser:
    def __init__(self):
        # Define the grammar rules (simplified for demonstration)
        self.grammar = {
            'E': [['T', 'E_prime']],
            'E_prime': [['+', 'T', 'E_prime'], ['ε']],
            'T': [['F', 'T_prime']],
            'T_prime': [['*', 'F', 'T_prime'], ['ε']],
            'F': [['id'], ['(', 'E', ')']]
        }
        self.terminals = {'+', '*', 'id', '(', ')', '$'}
        self.non_terminals = {'E', 'E_prime', 'T', 'T_prime', 'F'}

    def parse(self, tokens):
        """Simple recursive descent parser"""
        self.tokens = tokens + ['$']
        self.pos = 0
        try:
            result = self.parse_E()
            return result and self.pos == len(self.tokens) - 1
        except:
            return False

    def parse_E(self):
        return self.parse_T() and self.parse_E_prime()

    def parse_E_prime(self):
        if self.match('+'):
            self.consume('+')
            self.parse_T()
            self.parse_E_prime()
        # epsilon production - do nothing
        return True

    def parse_T(self):
        return self.parse_F() and self.parse_T_prime()

    def parse_T_prime(self):
        if self.match('*'):
            self.consume('*')
            self.parse_F()
            self.parse_T_prime()
        return True

    def parse_F(self):
        if self.match('id'):
            self.consume('id')
            return True
        elif self.match('('):
            self.consume('(')
            self.parse_E()
            self.consume(')')
            return True
        return False

    def match(self, token):
        return self.pos < len(self.tokens) and self.tokens[self.pos] == token

    def consume(self, token):
        if self.match(token):
            self.pos += 1
            return True
        raise Exception(f"Expected {token}")

# Test the parser
parser = CFGParser()
test_inputs = [
    ['id'],
    ['id', '+', 'id'],
    ['id', '*', 'id'],
    ['id', '+', 'id', '*', 'id'],
    ['(', 'id', '+', 'id', ')']
]

print("CFG Parser Test Results:")
for tokens in test_inputs:
    result = parser.parse(tokens[:])  # pass copy of tokens
    print(f"Tokens: {tokens} -> Parsed: {result}")
